// Java 25 exam prep - StringBuilder
// Learn: mutate one builder with append, insert, delete, and reverse.
StringBuilder builder = new StringBuilder("ID");
builder.append('-').append(42); // append mutates this same builder.
builder.insert(0, '[');
builder.append(']');
builder.delete(0, 1);
builder.delete(builder.length() - 1, builder.length());
builder.reverse();
System.out.println(builder);
